define('taoQtiTestPreviewer/previewer/plugins/content/enhancedReadOnlyMode',['jquery', 'lodash', 'i18n', 'taoTests/runner/plugin'], function ($, _, __, pluginFactory) {
  'use strict';

  return pluginFactory({
    name: 'EnhancedReadOnlyMode',
    init() {
      var testRunner = this.getTestRunner();
      var isPluginAllowed = () => {
        var config = testRunner.getConfig();
        return config.options.readOnly;
      };
      testRunner.after('renderitem', () => {
        if (isPluginAllowed()) {
          var $contentArea = testRunner.getAreaBroker().getContentArea();
          var $extendedTextinteractionTextAreas = $contentArea.find('.qti-extendedTextInteraction textarea.text-container');
          var $ckeEditorsContent = $contentArea.find('.qti-extendedTextInteraction div.cke_contents');
          if ($extendedTextinteractionTextAreas.length) {
            $extendedTextinteractionTextAreas.each(function () {
              this.style.height = "".concat(this.scrollHeight + 20, "px");
            });
          }
          if ($ckeEditorsContent.length) {
            $ckeEditorsContent.each(function () {
              var $ckeEditorContent = $(this);
              var $ckeEditorIFrame = $ckeEditorContent.find('iframe.cke_wysiwyg_frame');
              $ckeEditorIFrame.on('load', () => {
                setTimeout(() => {
                  var ckeEditorBody = $ckeEditorIFrame[0].contentWindow.document.querySelector('body');
                  $ckeEditorContent[0].style.height = "".concat(ckeEditorBody.scrollHeight + 20, "px");
                }, 0);
              });
            });
          }
        }
      });
    }
  });
});
