define('taoQtiTestPreviewer/previewer/plugins/navigation/submit/submit',['jquery', 'lodash', 'i18n', 'moment', 'ui/hider', 'ui/autoscroll', 'util/strPad', 'taoTests/runner/plugin', 'taoQtiItem/qtiCommonRenderer/helpers/PciResponse', 'taoQtiItem/runner/rendererStrategies', 'tpl!taoQtiTest/runner/plugins/templates/button', 'tpl!taoQtiTestPreviewer/previewer/plugins/navigation/submit/preview-console', 'tpl!taoQtiTestPreviewer/previewer/plugins/navigation/submit/preview-console-line', 'tpl!taoQtiTestPreviewer/previewer/plugins/navigation/submit/preview-console-closer'], function ($, _, __, moment, hider, autoscroll, strPad, pluginFactory, pciResponse, rendererStrategies, buttonTpl, consoleTpl, consoleLineTpl, consoleCloserTpl) {
  'use strict';
  var defaults = {
    submitTitle: __('Submit and show the result'),
    submitText: __('Submit'),
    submitIcon: 'forward'
  };
  return pluginFactory({
    name: 'submit',
    init() {
      var testRunner = this.getTestRunner();
      var pluginConfig = _.defaults(this.getConfig(), defaults);
      var isPluginAllowed = () => {
        var config = testRunner.getConfig();
        return !config.options.readOnly && rendererStrategies(config.options.view).getName() !== 'reviewRenderer';
      };
      var showConsole = () => {
        hider.show(this.controls.$console);
        hider.show(this.controls.$consoleBody);
        hider.show(this.controls.$consoleCloser);
        autoscroll(this.controls.$consoleBody.children().last(), this.controls.$consoleBody);
      };
      var hideConsole = () => {
        hider.hide(this.controls.$console);
        hider.hide(this.controls.$consoleCloser);
      };
      var addConsoleLine = (type, message) => {
        var data = {
          time: strPad(moment().format('HH:mm:ss'), 12, ' '),
          type: strPad(type || '', 18, ' '),
          message: strPad(message || '', 18, ' ')
        };
        this.controls.$consoleBody.append($(consoleLineTpl(data)));
      };
      var showResponses = (type, responses) => {
        _.forEach(responses, (response, identifier) => {
          addConsoleLine(type, strPad("".concat(identifier, ": "), 15, ' ') + _.escape(pciResponse.prettyPrint(response)));
        });
      };
      this.controls = {
        $button: $(buttonTpl({
          control: 'submit',
          title: pluginConfig.submitTitle,
          icon: pluginConfig.submitIcon,
          text: pluginConfig.submitText
        })),
        $console: $(consoleTpl()),
        $consoleCloser: $(consoleCloserTpl())
      };
      this.controls.$consoleBody = this.controls.$console.find('.preview-console-body');
      this.controls.$button.on('click', e => {
        e.preventDefault();
        if (this.getState('enabled') !== false) {
          this.disable();
          testRunner.trigger('submititem');
        }
      });
      this.controls.$consoleCloser.on('click', e => {
        e.preventDefault();
        hideConsole();
      });
      if (!isPluginAllowed()) {
        this.hide();
      }
      this.disable();
      testRunner.on('render', () => {
        if (isPluginAllowed()) {
          this.show();
        } else {
          this.hide();
        }
      }).on('submitresponse', responses => {
        showResponses(__('Submitted data'), responses);
        showConsole();
      }).on('scoreitem', responses => {
        if (responses.itemSession) {
          showResponses(__('Output data'), responses.itemSession);
          showConsole();
        }
      }).on('enablenav', () => {
        this.enable();
      }).on('disablenav', () => {
        this.disable();
      });
    },
    render() {
      var $container = this.getAreaBroker().getContainer();
      var $navigation = this.getAreaBroker().getNavigationArea();
      $navigation.append(this.controls.$button);
      $navigation.append(this.controls.$consoleCloser);
      $container.append(this.controls.$console);
    },
    destroy() {
      _.forEach(this.controls, $el => $el.remove());
      this.controls = null;
    },
    enable() {
      this.controls.$button.prop('disabled', false).removeClass('disabled');
    },
    disable() {
      this.controls.$button.prop('disabled', true).addClass('disabled');
    },
    show() {
      hider.show(this.controls.$button);
    },
    hide() {
      _.forEach(this.controls, hider.hide);
    }
  });
});
