define('taoQtiTestPreviewer/previewer/proxy/itemDataHandlers',['module', 'context', 'lodash', 'core/moduleLoader'], function (module, context, _, moduleLoader) {
  'use strict';

  var moduleConfig = module.config();
  var handlers = [];
  if (moduleConfig.handlers) {
    moduleLoader({}, _.isFunction).addList(moduleConfig.handlers).load(context.bundle).then(data => handlers = data);
  }
  return function itemDataHandlers(itemData) {
    if (!handlers.length) {
      return Promise.resolve(itemData);
    }
    if (handlers.length === 1) {
      return handlers[0](itemData);
    } else {
      return handlers.reduce(function (prev, cur) {
        return prev.then(updateItemData => cur(updateItemData)).catch(cur().reject);
      }, handlers[0](itemData));
    }
  };
});
