define('taoQtiTestPreviewer/previewer/adapter/test/qtiTest',['lodash', 'core/promiseQueue', 'core/request', 'util/url', 'core/logger', 'taoQtiTestPreviewer/previewer/component/test/qtiTest', 'ui/feedback', 'taoQtiTestPreviewer/previewer/component/topBlock/topBlock'], function (_, promiseQueue, request, urlUtil, loggerFactory, qtiTestPreviewerFactory, feedback, topBlockFactory) {
  'use strict';

  var taoExtension = 'taoQtiTestPreviewer';
  var testPreviewerController = 'TestPreviewer';
  var logger = loggerFactory('taoQtiTestPreviewer/previewer');
  var defaultPlugins = [{
    module: 'taoQtiTestPreviewer/previewer/plugins/content/cloneLogoInTestPreview',
    bundle: 'taoQtiTestPreviewer/loader/qtiPreviewer.min',
    category: 'content'
  }];
  var transformConfiguration = config => {
    var plugins = Array.isArray(config.plugins) ? [...defaultPlugins, ...config.plugins] : defaultPlugins;
    var {
      view,
      readOnly,
      fullPage,
      hideActionBars,
      pluginsOptions
    } = config;
    var options = _.omit({
      view,
      readOnly,
      fullPage,
      hideActionBars
    }, _.isUndefined);
    return request({
      url: urlUtil.route('configuration', testPreviewerController, taoExtension),
      noToken: true
    }).then(response => {
      var configuration = response.data;
      configuration.providers.plugins = [...configuration.providers.plugins, ...plugins];
      _.assign(configuration.options, options);
      if (pluginsOptions) {
        if (!configuration.options.plugins) {
          configuration.options.plugins = {};
        }
        _.assign(configuration.options.plugins, pluginsOptions);
      }
      return configuration;
    });
  };
  return {
    name: 'qtiTest',
    install() {
      this.queue = promiseQueue();
    },
    init(testUri) {
      var config = arguments.length > 1 && arguments[1] !== undefined ? arguments[1] : {};
      return transformConfiguration(config).then(testPreviewConfig => {
        testPreviewConfig.options.testUri = testUri;
        var topBlock = null;
        var previewComponent = qtiTestPreviewerFactory(window.document.body, testPreviewConfig).on('ready', function (runner) {
          topBlock = topBlockFactory(window.document.body, {
            isTest: testPreviewConfig.options.review.scope === 'test',
            title: runner.getTestMap().title,
            onClose: () => {
              runner.trigger('exit');
            }
          });
        }).on('error', function (err) {
          if (topBlock) {
            topBlock.destroy();
            topBlock = null;
          }
          if (!_.isUndefined(err.message)) {
            feedback().error(err.message);
          }
          logger.error(err);
        }).on('destroy', () => {
          if (topBlock) {
            topBlock.destroy();
            topBlock = null;
          }
        });
        return previewComponent;
      });
    },
    destroy() {
      this.queue = null;
      return Promise.resolve();
    }
  };
});
