define('taoQtiTestPreviewer/previewer/plugins/content/cloneLogoInTestPreview',['jquery', 'taoTests/runner/plugin'], function ($, pluginFactory) {
  'use strict';

  return pluginFactory({
    name: 'cloneLogoInTestPreview',
    init() {
      var testRunner = this.getTestRunner();
      testRunner.after('ready', () => {
        $('#tao-main-logo').clone().appendTo('.previewer-test-component header');
      });
    }
  });
});
