define('taoQtiTestPreviewer/previewer/component/topBlock/topBlock',['jquery', 'lodash', 'i18n', 'ui/component', 'tpl!taoQtiTestPreviewer/previewer/component/topBlock/tpl/topBlock', 'tpl!taoQtiTestPreviewer/previewer/component/topBlock/tpl/topBlockData', 'css!taoQtiTestPreviewer/previewer/component/topBlock/css/topBlock'], function ($, _, __, componentFactory, topBlockTpl, topBlockDataTpl) {
  'use strict';
  function topBlockFactory(container, config) {
    var topBlock = componentFactory().setTemplate(topBlockTpl).on('init', function () {
      this.render(container);
    }).on('render', function () {
      var $info = $(topBlockDataTpl({
        name: config.isTest ? __('Test Preview:') : __('Item Preview:'),
        title: config.title
      }));
      var $element = this.getElement();
      $element.find('.top-block-preview-info').append($info);
      $element.find('.close').on('click', config.onClose);
      var $icon = $element.find('.top-block-preview-collapser .icon');
      var transitionDone = 'transition-done';
      $element.find('.top-block-preview-collapser').on('click', () => {
        $icon.toggleClass('icon-up');
        $icon.toggleClass('icon-down');
        $element.toggleClass('open');
        $element.toggleClass('close');
        if (!$element.hasClass(transitionDone)) {
          setTimeout(() => {
            $element.addClass(transitionDone);
          }, 500);
        } else {
          $element.removeClass(transitionDone);
        }
      });
      this.trigger('ready');
    });
    _.defer(function () {
      topBlock.init(config);
    });
    return topBlock;
  }
  return topBlockFactory;
});
