define('taoQtiTestPreviewer/previewer/proxy/test',['core/promiseQueue', 'core/request', 'util/url', 'taoQtiTest/runner/helpers/map', 'taoQtiTestPreviewer/previewer/proxy/itemDataHandlers'], function (promiseQueue, request, urlUtil, mapHelper, itemDataHandlers) {
  'use strict';

  var serviceControllerInit = 'TestPreviewer';
  var serviceControllerGetItem = 'Previewer';
  var serviceExtension = 'taoQtiTestPreviewer';
  var testSessionStates = Object.freeze({
    initial: 0,
    interacting: 1,
    modalFeedback: 2,
    suspended: 3,
    closed: 4
  });
  var itemSessionStates = Object.freeze({
    initial: 0,
    interacting: 1,
    modalFeedback: 2,
    suspended: 3,
    closed: 4,
    solution: 5,
    review: 6
  });
  function updateTestContextWithItem(testMap, position, testContext, presetMap) {
    var jump = mapHelper.getJump(testMap, position);
    var item = mapHelper.getItemAt(testMap, position);
    if (!item) {
      return;
    }
    testContext.testPartId = jump.part;
    testContext.sectionId = jump.section;
    testContext.itemIdentifier = jump.identifier;
    testContext.itemSessionState = itemSessionStates.initial;
    testContext.options = createContextOptions(item, presetMap);
    testContext.allowSkipping = item.allowSkipping;
  }
  function createContextOptions(item, presetMap) {
    var options = {};
    presetMap.forEach(category => {
      var pluginId = Object.keys(category)[0];
      var categoryId = category[pluginId];
      if (item.categories.includes(categoryId)) {
        options[pluginId] = true;
      }
    });
    return options;
  }
  return {
    name: 'qtiTestPreviewerProxy',
    install() {
      this.queue = promiseQueue();
    },
    init(configs) {
      this.itemStore = {};
      return request({
        url: urlUtil.route('init', serviceControllerInit, serviceExtension),
        data: {
          testUri: configs.options.testUri
        },
        noToken: true
      }).then(response => {
        var data = response.data;
        this.builtTestMap = mapHelper.reindex(data.testMap);
        this.presetMap = data.presetMap || [];
        delete data.presetMap;
        var firstJump = this.builtTestMap.jumps[0] || {};
        var firstItem = mapHelper.getItemAt(this.builtTestMap, 0);
        data.testContext = {
          itemIdentifier: firstJump.identifier,
          itemPosition: 0,
          itemSessionState: 0,
          testPartId: firstJump.part,
          sectionId: firstJump.section,
          canMoveBackward: true,
          state: testSessionStates.interacting,
          attempt: 1,
          options: createContextOptions(firstItem, this.presetMap),
          allowSkipping: firstItem.allowSkipping
        };
        return data;
      });
    },
    destroy() {
      this.queue = null;
      if (this.itemStore) {
        this.itemStore = null;
      }
      return Promise.resolve();
    },
    getItem(itemIdentifier) {
      if (itemIdentifier in this.itemStore) {
        return Promise.resolve(this.itemStore[itemIdentifier]);
      } else {
        var {
          uri
        } = mapHelper.getItem(this.builtTestMap, itemIdentifier) || {};
        if (!uri) {
          throw new Error("There is no item ".concat(itemIdentifier, " in the testMap!"));
        }
        return request({
          url: urlUtil.route('getItem', serviceControllerGetItem, serviceExtension),
          data: {
            serviceCallId: 'previewer',
            itemUri: uri
          },
          noToken: true
        }).then(data => {
          data.itemData = data.content;
          data.itemIdentifier = data.content.data.identifier;
          data.itemState = {};
          this.itemStore[itemIdentifier] = data;
          return data;
        }).then(itemData => itemDataHandlers(itemData));
      }
    },
    submitItem(itemIdentifier, state, response) {
      var params = arguments.length > 3 && arguments[3] !== undefined ? arguments[3] : {};
      var {
        uri
      } = mapHelper.getItem(this.builtTestMap, itemIdentifier) || {};
      if (!uri) {
        return Promise.reject(new Error("There is no item ".concat(itemIdentifier, " in the testMap!")));
      }
      var url = urlUtil.route('submitItem', serviceControllerGetItem, serviceExtension, {
        itemUri: uri
      });
      var requestData = Object.assign({
        itemResponse: JSON.stringify(response),
        itemState: JSON.stringify(state)
      }, params);
      return request({
        url: url,
        data: requestData,
        method: 'POST',
        noToken: true
      }).then(result => {
        var itemData = this.itemStore[itemIdentifier];
        return {
          displayFeedbacks: result.displayFeedback || false,
          itemSession: result.itemSession || {},
          feedbacks: itemData && itemData.itemData && itemData.itemData.data && itemData.itemData.data.feedbacks || {}
        };
      }).catch(err => {
        return Promise.reject(err);
      });
    },
    callItemAction(itemIdentifier, action) {
      var params = arguments.length > 2 && arguments[2] !== undefined ? arguments[2] : {};
      var dataHolder = this.getDataHolder();
      var testContext = dataHolder.get('testContext');
      var testMap = dataHolder.get('testMap');
      var actions = {
        move: () => {
          if (params.direction === 'next' || action === 'skip') {
            if (params.scope === 'testPart') {
              var testPartPosition = testMap.parts[testContext.testPartId].position;
              var nextPartsSorted = Object.values(testMap.parts).filter(p => p.position > testPartPosition).sort((a, b) => a.position - b.position);
              if (nextPartsSorted.length === 0) {
                testContext.state = testSessionStates.closed;
              } else {
                testContext.itemPosition = Math.min(testMap.stats.total - 1, nextPartsSorted[0].position);
              }
            } else {
              if (testContext.itemPosition + 1 >= testMap.stats.total) {
                testContext.state = testSessionStates.closed;
              } else {
                testContext.itemPosition = Math.min(testMap.stats.total - 1, testContext.itemPosition + 1);
              }
            }
          }
          if (params.direction === 'previous') {
            testContext.itemPosition = Math.max(0, testContext.itemPosition - 1);
          }
          if (params.direction === 'jump' && params.ref >= 0) {
            testContext.itemPosition = params.ref;
          }
          updateTestContextWithItem(testMap, testContext.itemPosition, testContext, this.presetMap);
          return {
            testContext,
            testMap
          };
        },
        flagItem: () => Promise.resolve()
      };
      actions.skip = actions.move;
      if (params.itemState) {
        this.itemStore[itemIdentifier].itemState = params.itemState;
      }
      if (typeof actions[action] === 'function') {
        return actions[action]();
      }
    },
    callTestAction() {
      return Promise.resolve();
    }
  };
});
